			// Test encryption
			result, err := transformer.TransformToStorage(ctx, tc.originalData, nil)
			if tc.encryptErr != nil {
				if err == nil {
					t.Fatalf("TransformToStorage() expected error %q, got nil", tc.failureMessage)
				}
				if err.Error() != tc.failureMessage {
					t.Errorf("TransformToStorage() error = %v, want %v", err, tc.encryptErr)
				}
				return
			}
			if err != nil {
				t.Fatalf("TransformToStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(result, tc.encryptedData) {
				t.Errorf("TransformToStorage() = %v, want %v", result, tc.encryptedData)
			}

			// Test decryption
			result, stale, err := transformer.TransformFromStorage(ctx, tc.encryptedData, nil)
			if tc.decryptErr != nil {
