		encryptedData  []byte
		encryptErr     error
		decryptErr     error
		stale          bool
		shouldFail     bool
		failureMessage string
	}{
		{
			name:          "simple encryption",
			originalData:  []byte("hello"),
			encryptedData: []byte("enc_hello"),
			shouldFail:    false,
		},
		{
			name:           "empty data",
			originalData:   []byte{},
			encryptedData:  []byte{},
			shouldFail:     false,
		},
		{
			name:           "encryption error",
			originalData:   []byte("data"),
			encryptErr:     fmt.Errorf("encryption failed"),
			shouldFail:     true,
			failureMessage: "encryption failed",
		},
		{
			name:           "decryption error",
			originalData:   []byte("data"),
			encryptedData:  []byte("encrypted"),
			decryptErr:     fmt.Errorf("decryption failed"),
			shouldFail:     true,
			failureMessage: "decryption failed",
		},
		{
			name:          "large data",
			originalData:  bytes.Repeat([]byte("x"), 10000),
			encryptedData: bytes.Repeat([]byte("y"), 10000),
			shouldFail:    false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			transformer := &mockTransformer{
				encryptedData: tc.encryptedData,
				decryptedData: tc.originalData,
				encryptErr:    tc.encryptErr,
				decryptErr:    tc.decryptErr,
				staleFlag:     tc.stale,
			}

			ctx := context.Background()

			// Test encryption
			result, err := transformer.TransformToStorage(ctx, tc.originalData, nil)
			if tc.encryptErr != nil {
				if err == nil {
					t.Fatalf("TransformToStorage() expected error %q, got nil", tc.failureMessage)
				}
				if err.Error() != tc.failureMessage {
					t.Errorf("TransformToStorage() error = %v, want %v", err, tc.encryptErr)
				}
				return
			}
			if err != nil {
				t.Fatalf("TransformToStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(result, tc.encryptedData) {
				t.Errorf("TransformToStorage() = %v, want %v", result, tc.encryptedData)
			}

			// Test decryption
			result, stale, err := transformer.TransformFromStorage(ctx, tc.encryptedData, nil)
			if tc.decryptErr != nil {
				if err == nil {
					t.Fatalf("TransformFromStorage() expected error %q, got nil", tc.failureMessage)
				}
				return
			}
			if err != nil {
				t.Fatalf("TransformFromStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(result, tc.originalData) {
				t.Errorf("TransformFromStorage() = %v, want %v", result, tc.originalData)
			}
			if stale != tc.stale {
				t.Errorf("TransformFromStorage() stale = %v, want %v", stale, tc.stale)
			}
		})
	}
}

// TestPrefixTransformerPrefixMatching tests that PrefixTransformer correctly matches prefixes.
func TestPrefixTransformerPrefixMatching(t *testing.T) {
	testCases := []struct {
		name            string
