		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
}

// TestPrefixTransformerDataContextPropagation tests that data context is propagated.
func TestPrefixTransformerDataContextPropagation(t *testing.T) {
	mockTrans := &mockTransformer{
		encryptedData: []byte("encrypted"),
		decryptedData: []byte("decrypted"),
	}

	transformer := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("pre:"),
			Transformer: mockTrans,
		},
	)

	ctx := context.Background()
	dataCtx := DefaultContext([]byte("authenticated_data"))

	// Test ToStorage with DataContext
	_, err := transformer.TransformToStorage(ctx, []byte("data"), dataCtx)
	if err != nil {
		t.Fatalf("TransformToStorage() unexpected error: %v", err)
	}

	// Test FromStorage with DataContext
	_, _, err = transformer.TransformFromStorage(ctx, []byte("pre:data"), dataCtx)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
}

// TestPrefixTransformerPrefixStripping tests that prefixes are stripped before transformation.
func TestPrefixTransformerPrefixStripping(t *testing.T) {
	mockTrans := &mockTransformer{
		decryptedData: []byte("result"),
	}

	transformer := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("prefix:"),
			Transformer: mockTrans,
		},
	)

	ctx := context.Background()
	inputData := []byte("prefix:payload_data")

	_, _, err := transformer.TransformFromStorage(ctx, inputData, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}

	// Verify that the transformer received the data without the prefix
	expectedPayload := []byte("payload_data")
	if !bytes.Equal(mockTrans.receivedData, expectedPayload) {
		t.Errorf("Transformer received %v, want %v", mockTrans.receivedData, expectedPayload)
	}
}

// TestPrefixTransformerPrefixPrepending tests that prefixes are prepended to output.
func TestPrefixTransformerPrefixPrepending(t *testing.T) {
	mockTrans := &mockTransformer{
		encryptedData: []byte("encrypted_payload"),
	}

	transformer := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("prefix:"),
			Transformer: mockTrans,
		},
	)

	ctx := context.Background()
	result, err := transformer.TransformToStorage(ctx, []byte("plaintext"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage() unexpected error: %v", err)
	}

	expected := []byte("prefix:encrypted_payload")
	if !bytes.Equal(result, expected) {
		t.Errorf("TransformToStorage() = %v, want %v", result, expected)
	}
}

// TestMultiplePrefixTransformersSequential tests multiple transformers are tried in order.
func TestMultiplePrefixTransformersSequential(t *testing.T) {
	trans1 := &mockTransformer{decryptedData: []byte("from_first")}
	trans2 := &mockTransformer{decryptedData: []byte("from_second")}
	trans3 := &mockTransformer{decryptedData: []byte("from_third")}

	transformer := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: trans1},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: trans2},
		PrefixTransformer{Prefix: []byte("third:"), Transformer: trans3},
	)

	testCases := []struct {
		name           string
		data           []byte
		expectedTrans  int
		expectedResult []byte
	}{
		{
			name:           "matches first",
			data:           []byte("first:data"),
			expectedTrans:  0,
			expectedResult: []byte("from_first"),
		},
		{
			name:           "matches second",
			data:           []byte("second:data"),
			expectedTrans:  1,
			expectedResult: []byte("from_second"),
		},
		{
			name:           "matches third",
			data:           []byte("third:data"),
			expectedTrans:  2,
			expectedResult: []byte("from_third"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			result, _, err := transformer.TransformFromStorage(ctx, tc.data, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(result, tc.expectedResult) {
				t.Errorf("TransformFromStorage() = %v, want %v", result, tc.expectedResult)
			}
		})
	}
}

// TestPrefixTransformerBinaryData tests transformers with binary data.
func TestPrefixTransformerBinaryData(t *testing.T) {
	binaryPrefix := []byte{0x00, 0x01, 0x02}
	binaryData := []byte{0xFF, 0xEE, 0xDD, 0xCC}
	binaryResult := []byte{0x11, 0x22, 0x33, 0x44}

	mockTrans := &mockTransformer{
		decryptedData: binaryResult,
	}

	transformer := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      binaryPrefix,
			Transformer: mockTrans,
		},
	)

	ctx := context.Background()
	input := append(binaryPrefix, binaryData...)

	result, _, err := transformer.TransformFromStorage(ctx, input, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if !bytes.Equal(result, binaryResult) {
		t.Errorf("TransformFromStorage() = %v, want %v", result, binaryResult)
	}

	// Test ToStorage with binary
	output, err := transformer.TransformToStorage(ctx, binaryData, nil)
	if err != nil {
		t.Fatalf("TransformToStorage() unexpected error: %v", err)
	}

	expectedOutput := append(binaryPrefix, mockTrans.encryptedData...)
	if !bytes.Equal(output, expectedOutput) {
		t.Errorf("TransformToStorage() = %v, want %v", output, expectedOutput)
	}
}
